# Custom JSON encoder for datetime
class DateTimeEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, (datetime, date)):
            return obj.isoformat()
        return super().default(obj)

class DateTimeDecoder(json.JSONDecoder):
    def __init__(self, *args, **kwargs):
        super().__init__(object_hook=self.object_hook, *args, **kwargs)

    def object_hook(self, obj):
        for key, value in obj.items():
            if isinstance(value, str) and key.endswith('_date'):
                try:
                    obj[key] = datetime.fromisoformat(value)
                except (ValueError, TypeError):
                    pass
        return obj

# Using custom encoder
now = datetime.now()
data_with_date = {"created_date": now, "name": "Test"}
json_with_date = json.dumps(data_with_date, cls=DateTimeEncoder, indent=2)
print(json_with_date)

# Reading with custom decoder
parsed_with_date = json.loads(json_with_date, cls=DateTimeDecoder)
print(f"Parsed datetime: {parsed_with_date['created_date']}")

# JSON schema validation
def validate_json(data, required_fields):
    """Validate required fields in JSON data"""
    missing = [field for field in required_fields if field not in data]
    if missing:
        raise ValueError(f"Missing required fields: {missing}")
    return True

try:
    validate_json(loaded_data, ['company', 'employees', 'metadata'])
    print("JSON validation passed")
except ValueError as e:
    print(f"Validation failed: {e}")

# Merging multiple JSON files
import glob

def merge_json_files(pattern, output_file):
    merged_data = []
    for filepath in glob.glob(pattern):
        with open(filepath, 'r', encoding='utf-8') as f:
            data = json.load(f)
            merged_data.extend(data if isinstance(data, list) else [data])

    with open(output_file, 'w', encoding='utf-8') as f:
        json.dump(merged_data, f, indent=2)

    return len(merged_data)

